SELECT ?hostCity ?hostCityLabel WHERE {
  VALUES ?gameType { wd:Q723331 wd:Q55651377 }
  ?olympics wdt:P31 ?gameType ;
             wdt:P580 ?startDate ;
             wdt:P3373 ?hostCity .
  ?hostCity rdfs:label ?hostCityLabel .
  FILTER (LANG(?hostCityLabel) = "en")
  FILTER (?startDate > NOW())
}
ORDER BY ASC(?startDate)
LIMIT 1

